1	type Customer = {
2	  yearsAsCustomer: number;
3	  quoteCount: number;
4	};
5	
6	type Item = {
7	  type: string;
8	  material: string;
9	  enchantment: number;
10	  cursed: boolean;
11	};
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSED_SURCHARGE_RATE = 0.5;
25	
26	const COMPONENT_BLOCK_SIZE = 3;
27	const COMPONENT_BLOCK_PREMIUM = 60;
28	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
29	
30	const componentPremium = (type: string, count: number): number =>
31	  count === COMPONENT_BLOCK_SIZE
32	    ? COMPONENT_BLOCK_PREMIUM
33	    : count * BASE_PREMIUMS[type];
34	
35	const itemSurcharge = (item: Item, basePremium: number): number =>
36	  item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
37	
38	export function quote(customer: Customer, items: Item[]): number {
39	  if (items.length === 0) return PROCESSING_FEE;
40	
41	  let basePremium = 0;
42	  let totalItemSurcharges = 0;
43	  const componentCounts: Record<string, number> = {};
44	
45	  for (const item of items) {
46	    if (COMPONENT_TYPES.has(item.type)) {
47	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
48	    } else {
49	      const itemBase = BASE_PREMIUMS[item.type];
50	      basePremium += itemBase;
51	      totalItemSurcharges += itemSurcharge(item, itemBase);
52	    }
53	  }
54	
55	  for (const type of Object.keys(componentCounts)) {
56	    basePremium += componentPremium(type, componentCounts[type]);
57	  }
58	
59	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
60	  return Math.ceil(basePremium + totalItemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE);
61	}
62	
63	export function claim() {
64	  return undefined;
65	}
