const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const itemSurcharge = (item: Item, basePremium: number): number => {
  let surcharge = 0;
  if (item.cursed) surcharge += basePremium * CURSED_SURCHARGE_RATE;
  if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  return surcharge;
};

